const yaml = require('js-yaml');
const doc = yaml.load($input.item.json.stdout || '') || { domains: [] };
const urls = (doc.domains || []).filter(d => d.ssl_check_url).map(d => ({ domain: d.domain, url: d.ssl_check_url }));
return urls.map(u => ({ json: u }));

// n8n's HEAD request returns headers; extract cert info from the response.
// In practice, openssl s_client gives the most reliable expiry. Use Execute Command for that.
const domain = $('Extract SSL URLs').item.json.domain;
const url = $('Extract SSL URLs').item.json.url;
const host = new URL(url).hostname;
return [{ json: { domain, host } }];

const enddateStr = ($input.item.json.stdout || '').trim();
const domain = $('Prep for openssl').item.json.domain;
if (!enddateStr) return [{ json: { domain, daysLeft: null, error: 'no enddate parsed' } }];
const expires = new Date(enddateStr);
const daysLeft = Math.floor((expires - Date.now()) / 86400000);
return [{ json: { domain, expires: expires.toISOString().slice(0,10), daysLeft } }];

const certs = ($input.item.json.json || []);
const critical = certs.filter(c => c.daysLeft !== null && c.daysLeft <= 3);
const soon = certs.filter(c => c.daysLeft !== null && c.daysLeft > 3 && c.daysLeft <= 14);
if (critical.length === 0 && soon.length === 0) return [];
const priority = critical.length > 0 ? 'P0' : 'P1';
const lines = [...critical, ...soon].map(c => `• ${c.domain}: ${c.daysLeft}d remaining`);
return [{ json: {
  priority,
  source: 'cert-watch',
  message: `${critical.length} cert${critical.length > 1 ? 's' : ''} ≤3d / ${soon.length} ≤14d:\n${lines.join('\n')}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/check/infrastructure'
}}];
